<template>
	<view class="container">
		<view class="header">
			<text class="title">库存管理</text>
		</view>
		
		<view class="inventory-stats">
			<view class="stat-card">
				<text class="stat-title">总库存</text>
				<text class="stat-value">{{ totalInventory }}</text>
				<text class="stat-unit">件</text>
			</view>
			<view class="stat-card">
				<text class="stat-title">库存周转</text>
				<text class="stat-value">{{ inventoryTurnover }}</text>
				<text class="stat-unit">天</text>
			</view>
			<view class="stat-card">
				<text class="stat-title">低库存</text>
				<text class="stat-value">{{ lowInventory }}</text>
				<text class="stat-unit">种</text>
			</view>
			<view class="stat-card">
				<text class="stat-title">库存预警</text>
				<text class="stat-value">{{ inventoryAlerts }}</text>
				<text class="stat-unit">条</text>
			</view>
		</view>
		
		<view class="inventory-section">
			<view class="section-header">
				<text class="section-title">库存列表</text>
				<text class="more">查看全部</text>
			</view>
			
			<view class="inventory-list">
				<view class="inventory-item" v-for="(item, index) in inventoryItems" :key="index">
					<view class="item-header">
						<text class="item-name">{{ item.product }}</text>
						<text class="item-code">{{ item.code }}</text>
					</view>
					
					<view class="item-details">
						<view class="detail-row">
							<text class="detail-label">当前库存：</text>
							<text class="detail-value">{{ item.currentStock }} 件</text>
						</view>
						<view class="detail-row">
							<text class="detail-label">安全库存：</text>
							<text class="detail-value">{{ item.safeStock }} 件</text>
						</view>
						<view class="detail-row">
							<text class="detail-label">单位：</text>
							<text class="detail-value">{{ item.unit }}</text>
						</view>
						<view class="detail-row">
							<text class="detail-label">库存位置：</text>
							<text class="detail-value">{{ item.location }}</text>
						</view>
					</view>
					
					<view class="item-actions">
						<button class="action-btn" @click="viewInventory(item.id)">查看详情</button>
						<button class="action-btn secondary" @click="adjustInventory(item.id)">调整库存</button>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			totalInventory: 12500,
			inventoryTurnover: 15,
			lowInventory: 3,
			inventoryAlerts: 2,
			inventoryItems: [
				{
					id: 'I001',
					product: '产品A',
					code: 'PROD-A001',
					currentStock: 2500,
					safeStock: 500,
					unit: '件',
					location: '仓库A-1区'
				},
				{
					id: 'I002',
					product: '产品B',
					code: 'PROD-B001',
					currentStock: 1200,
					safeStock: 300,
					unit: '件',
					location: '仓库A-2区'
				},
				{
					id: 'I003',
					product: '产品C',
					code: 'PROD-C001',
					currentStock: 350,
					safeStock: 500,
					unit: '件',
					location: '仓库B-1区'
				},
				{
					id: 'I004',
					product: '产品D',
					code: 'PROD-D001',
					currentStock: 4200,
					safeStock: 1000,
					unit: '件',
					location: '仓库B-2区'
				}
			]
		};
	},
	methods: {
		viewInventory(id) {
			uni.showToast({
				title: `查看库存#${id}`,
				icon: 'none'
			});
		},
		adjustInventory(id) {
			uni.showToast({
				title: `调整库存#${id}`,
				icon: 'none'
			});
		}
	}
};
</script>

<style scoped>
